CREATE TABLE tdoll_skins ( -- 人形皮肤表
  row_id INTEGER PRIMARY KEY, -- 行号
  tdoll_name TEXT NOT NULL UNIQUE, -- 人形名称
  skin_list TEXT NOT NULL CHECK(TRIM(skin_list) <> '') -- 皮肤列表
);

CREATE TABLE resource_status ( -- 资源表
  row_id INTEGER PRIMARY KEY, -- 行号
  resource_name TEXT NOT NULL UNIQUE CHECK(resource_name IN ('人力','弹药','口粮','零件','心智核心')), -- 资源项
  amount INTEGER NOT NULL CHECK(amount >= 0) -- 数量
);

CREATE TABLE total_chapters ( -- 总章节表
  row_id INTEGER PRIMARY KEY, -- 行号，按世界书战役文件顺序排列
  chapter_name TEXT NOT NULL UNIQUE, -- 章节名
  chapter_type TEXT NOT NULL CHECK(chapter_type IN ('主线','支线','活动')), -- 类型
  chapter_status TEXT NOT NULL CHECK(chapter_status IN ('未开始','进行中','已完成')) -- 状态
);

CREATE TABLE story_flags ( -- 剧情标记表
  row_id INTEGER PRIMARY KEY, -- 行号
  flag_name TEXT NOT NULL UNIQUE, -- 标记名称
  is_triggered TEXT NOT NULL CHECK(is_triggered IN ('是','否')) -- 是否触发
);

